def relu(x):
    return max(0.0, float(x))

def score_many(rows):
    out = []
    for row in rows:
        h1 = []
        for i in range(len(WEIGHTS['l1_b'])):
            val = float(WEIGHTS['l1_b'][i]) + sum(float(r) * float(w) for r, w in zip(row, WEIGHTS['l1_w'][i]))
            h1.append(relu(val))
        h2 = []
        for i in range(len(WEIGHTS['l2_b'])):
            val = float(WEIGHTS['l2_b'][i]) + sum(float(h) * float(w) for h, w in zip(h1, WEIGHTS['l2_w'][i]))
            h2.append(relu(val))
        val3 = float(WEIGHTS['l3_b'][0]) + sum(float(h) * float(w) for h, w in zip(h2, WEIGHTS['l3_w'][0]))
        out.append(val3)
    return out
